use bitset::BitSet;

#[test]
fn test_set_and_test() {
    let mut bs = BitSet::new(64);
    assert!(!bs.test(5));
    bs.set(5);
    assert!(bs.test(5));
    assert!(!bs.test(6));
}

#[test]
fn test_clear() {
    let mut bs = BitSet::new(64);
    bs.set(10);
    bs.clear(10);
    assert!(!bs.test(10));
}

#[test]
fn test_large_index() {
    let mut bs = BitSet::new(256);
    bs.set(200);
    assert!(bs.test(200));
    assert!(!bs.test(199));
}

#[test]
fn test_union() {
    let mut a = BitSet::new(64);
    let mut b = BitSet::new(64);
    a.set(1); a.set(3);
    b.set(2); b.set(3);
    let c = a.union(&b);
    assert!(c.test(1) && c.test(2) && c.test(3));
}

#[test]
fn test_intersection() {
    let mut a = BitSet::new(64);
    let mut b = BitSet::new(64);
    a.set(1); a.set(3);
    b.set(2); b.set(3);
    let c = a.intersection(&b);
    assert!(!c.test(1) && !c.test(2) && c.test(3));
}

#[test]
fn test_count() {
    let mut bs = BitSet::new(64);
    bs.set(0); bs.set(10); bs.set(63);
    assert_eq!(bs.count(), 3);
}

pub struct BitSet {
    data: Vec<u64>,
    size: usize,
}

impl BitSet {
    pub fn new(size: usize) -> Self {
        let words = (size + 63) / 64;
        BitSet { data: vec![0u64; words], size }
    }

    pub fn set(&mut self, bit: usize) {
        let (word, offset) = (bit / 64, bit % 64);
        self.data[word] |= 1u64 << offset;
    }

    pub fn clear(&mut self, bit: usize) {
        let (word, offset) = (bit / 64, bit % 64);
        self.data[word] &= !(1u64 << offset);
    }

    pub fn test(&self, bit: usize) -> bool {
        let (word, offset) = (bit / 64, bit % 64);
        (self.data[word] >> offset) & 1 == 1
    }

    pub fn union(&self, other: &BitSet) -> BitSet {
        let mut result = BitSet::new(self.size);
        for i in 0..self.data.len() {
            result.data[i] = self.data[i] | other.data[i];
        }
        result
    }

    pub fn intersection(&self, other: &BitSet) -> BitSet {
        let mut result = BitSet::new(self.size);
        for i in 0..self.data.len() {
            result.data[i] = self.data[i] & other.data[i];
        }
        result
    }

    pub fn count(&self) -> usize {
        self.data.iter().map(|w| w.count_ones() as usize).sum()
    }
}
